// // This module is designed to select between two inputs based on a selector signal.
// When sel is high, y0 is assigned the value of a, and y1 is assigned 0.
// When sel is low, y0 is assigned 0, and y1 is assigned the value of a.
module demux_1to2 (
    input a,
    input sel,
    output y0,
    output y1
);

    assign y0 = sel ? 0 : a;
    assign y1 = sel ? a : 0;

endmodule

